// ============================================================
// FTI OS — N02-Config — SOURCE DE VÉRITÉ UNIQUE
// Tous les champs produits ici — jamais reconstruits ailleurs
// ============================================================
const odooUrl    = $env.ODOO_URL    || 'https://fredtrade-sn.odoo.com';
const token      = $env.ODOO_BEARER_TOKEN || '';
const authHeader = 'Bearer ' + token;

// Variables deal
const dealName   = $env.DEAL_NAME   || 'DEAL_NAME_NON_DEFINI';
const docName    = $env.DOC_NAME    || 'DOC_NAME_NON_DEFINI';
const dropboxUrl = $env.DROPBOX_URL || 'https://www.dropbox.com/';
const folderName = $env.FOLDER_NAME || 'BUYER_BANK';
const status     = $env.STATUS      || 'WAITING_CLIENT_SIGNATURE';
const tags       = $env.TAGS        || 'FTI_OS';
const docType    = $env.DOC_TYPE    || 'CLIENT_APPLICATION';

// Endpoints — centralisés ici
const docSearchUrl  = odooUrl + '/json/2/documents.document/search_read';
const docCreateUrl  = odooUrl + '/json/2/documents.document/create';
const crmSearchUrl  = odooUrl + '/json/2/crm.lead/search_read';
const chatterUrl    = odooUrl + '/json/2/mail.message/create';

// Payload folder search — construit ici
const searchFolderBody = JSON.stringify({
  domain: [['name','ilike',folderName],['type','=','folder']],
  fields: ['id','name','folder_id'],
  limit: 10
});

// Payload CRM search — limit:1 forcé
const searchCRMBody = JSON.stringify({
  domain: [['name','ilike',dealName]],
  fields: ['id','name','stage_id','tag_ids'],
  limit: 1
});

return [{json:{
  // Auth — toujours présent
  odooUrl, token, authHeader,
  // Deal
  dealName, docName, dropboxUrl, folderName, status, tags, docType,
  // Endpoints
  docSearchUrl, docCreateUrl, crmSearchUrl, chatterUrl,
  // Payloads pré-construits
  searchFolderBody, searchCRMBody
}}];

// N04 — AfterFolder
// Reçoit résultat SearchFolder + enrichit ctx avec folderId
const ctx = $('N02-Config').first().json;
const records = $input.item.json.records || [];
const folderFound = records.length > 0;
const folderId    = folderFound ? records[0].id   : null;
const folderLabel = folderFound ? records[0].name : null;

// Payload anti-doublon construit ici
const checkDocBody = folderFound ? JSON.stringify({
  domain: [['name','ilike',ctx.docName],['folder_id','=',folderId]],
  fields: ['id','name','url','folder_id'],
  limit: 1
}) : null;

// Propagation complète du contexte N02 + enrichissement
return [{json:{
  ...ctx,
  folderId, folderLabel, folderFound, checkDocBody
}}];

// N07 — AfterDoc — REFACTOR v2.2
// Context garanti via N04-AfterFolder (qui porte déjà N02)
const ctx = $('N04-AfterFolder').first().json;

// Parsing robuste — gère {} et [] 
const raw = $input.item.json;
const records = Array.isArray(raw.records) ? raw.records
              : (Array.isArray(raw) ? raw : []);

const docCount    = records.length;
const docAbsent   = docCount === 0;
const existingDoc = docAbsent ? null : records[0];

// Payload create construit ici si doc absent
const createDocBody = docAbsent ? JSON.stringify({
  vals_list: {
    name:      ctx.docName,
    type:      'url',
    url:       ctx.dropboxUrl,
    folder_id: ctx.folderId
  }
}) : null;

// Propagation complète — authHeader garanti
return [{json:{
  ...ctx,
  docCount, docAbsent, existingDoc, createDocBody
}}];

// N11 — AfterCRM — REFACTOR v2.2
// Context garanti via N07-AfterDoc (chaîne complète N02→N04→N07)
const ctx = $('N07-AfterDoc').first().json;

const records  = $input.item.json.records || [];
const leadId   = records.length > 0 ? records[0].id   : null;
const leadName = records.length > 0 ? records[0].name : null;

// Payload chatter construit ici
const chatterBody = leadId ? JSON.stringify({
  vals_list: [{
    model:        'crm.lead',
    res_id:       leadId,
    body:         '<p><b>FTI OS — Référence documentaire créée</b></p>' +
                  '<p><b>Deal :</b> '     + ctx.dealName    + '</p>' +
                  '<p><b>Document :</b> ' + ctx.docName     + '</p>' +
                  '<p><b>Dossier :</b> '  + ctx.folderLabel + '</p>' +
                  '<p><b>Type :</b> URL Odoo — Dropbox HTTPS</p>' +
                  '<p><b>Lien :</b> <a href="' + ctx.dropboxUrl + '">' + ctx.dropboxUrl + '</a></p>' +
                  '<hr/>' +
                  '<p>Status : <b>' + ctx.status + '</b></p>' +
                  '<p>Tags : ' + ctx.tags + '</p>' +
                  '<p><small>Source : Claude FTI OS — Template v2.2</small></p>',
    message_type: 'comment'
  }]
}) : null;

// authHeader toujours présent via ctx
return [{json:{
  ...ctx,
  leadId, leadName, chatterBody
}}];
